// === DETECT EMBEDDING MODEL - Trouve le bon tag d'embeddinggemma ===
const tagsResp = $input.first().json;
const originalItems = $('Input').all();
const articles = originalItems.map(i => i.json);
const BATCH_SIZE = 10;

const availableModels = (tagsResp && tagsResp.models) ? tagsResp.models.map(m => m.name) : [];
console.log('=== Modeles Ollama disponibles ===');
availableModels.forEach(m => console.log('  - ' + m));

// Chercher un modele d'embedding adequat (priorite : 300m > latest > tout autre embeddinggemma > nomic-embed-text)
const preferred = ['embeddinggemma:300m', 'embeddinggemma:latest', 'embeddinggemma'];
let selectedModel = null;
for (const p of preferred) {
  if (availableModels.includes(p)) { selectedModel = p; break; }
}
if (!selectedModel) {
  // Tout modele commencant par embeddinggemma
  const found = availableModels.find(m => m.toLowerCase().startsWith('embeddinggemma'));
  if (found) selectedModel = found;
}
if (!selectedModel) {
  // Fallback nomic-embed-text
  const fallback = availableModels.find(m => m.toLowerCase().startsWith('nomic-embed-text'));
  if (fallback) {
    selectedModel = fallback;
    console.log('[WARN] embeddinggemma absent - fallback sur ' + fallback);
  }
}

if (!selectedModel) {
  throw new Error('Aucun modele d\'embedding installe sur Ollama. Modeles disponibles: ' + availableModels.join(', ') + '. Lancez : ollama pull embeddinggemma:300m');
}

console.log('=> Modele d\'embedding selectionne : ' + selectedModel);

// Preparer les batches en injectant le modele detecte dans chaque batch
const batches = [];
for (let i = 0; i < articles.length; i += BATCH_SIZE) {
  const batch = articles.slice(i, i + BATCH_SIZE);
  const texts = batch.map(a =>
    ((a.title || '') + ' ' + (a.abstract || '')).trim().substring(0, 1000) || 'no content'
  );
  batches.push({ json: { texts, model: selectedModel, batchIndex: Math.floor(i / BATCH_SIZE), batchSize: batch.length } });
}

console.log('Embedding: ' + articles.length + ' articles -> ' + batches.length + ' batches de ' + BATCH_SIZE + ' (modele=' + selectedModel + ')');
return batches;

// === EXPAND - Matche embeddings <-> articles ===
const responses = $input.all();
const originalItems = $('Input').all();
const articles = originalItems.map(i => i.json);
const BATCH_SIZE = 10;

const results = [];
for (let r = 0; r < responses.length; r++) {
  const resp = responses[r].json;
  // Ollama renvoie 'embeddings' (array d'arrays) pour /api/embed
  // ou 'embedding' (single array) pour /api/embeddings
  let embeddings = [];
  if (resp && Array.isArray(resp.embeddings)) embeddings = resp.embeddings;
  else if (resp && Array.isArray(resp.embedding)) embeddings = [resp.embedding];
  const start = r * BATCH_SIZE;
  const end = Math.min(start + BATCH_SIZE, articles.length);
  for (let i = start; i < end; i++) {
    results.push({
      json: {
        ...articles[i],
        embedding: embeddings[i - start] || []
      }
    });
  }
}

const withEmb = results.filter(r => r.json.embedding && r.json.embedding.length > 0).length;
console.log('Embedding complete: ' + withEmb + '/' + results.length + ' avec embeddings');
if (withEmb === 0) {
  console.log('[WARN] Aucun embedding genere - verifier les logs du proxy/relay.');
}
return results;
